// ignore_for_file: lines_longer_than_80_chars

/// Visual style of a [BTAlert].
enum BTAlertVariant {
  info,
  success,
  error,
  warning,
  neutral,

  /// Dark-background variant — uses [BTColorTheme.bg.inverse] as background
  /// and [BTColorTheme.text.inverse] for text/icons.
  neutralDark,
}

// ignore_for_file: lines_longer_than_80_chars

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import '../button-link/button_link.widget.dart';
import 'package:btech_ui/src/components/molecules/alert/alert.types.dart';
import 'package:btech_ui/src/components/molecules/alert/internal/alert.icons.dart';
import 'package:btech_ui/src/components/molecules/alert/internal/alert.toast.dart';
import 'package:flutter/material.dart';

/// BTAlert — contextual feedback banner.
///
/// Figma: node 681:11285 (light) · 4799:3868 (dark)
/// https://www.figma.com/design/WANr9drWYNYbMPuT2sMeHi/Btech---Design-System?node-id=4799-3868
///
/// Without description: `[icon] [label] [action-link?] [dismiss?]`
/// With description:    `[icon] [label + description + link?] [action-btn?] [dismiss?]`
///
/// ```dart
/// // Simple
/// BTAlert(variant: BTAlertVariant.success, label: 'Saved!')
///
/// // With description + link + action + dismiss
/// BTAlert(
///   variant: BTAlertVariant.error,
///   label: 'Something went wrong',
///   description: 'Please try again later.',
///   linkLabel: 'Learn more',
///   actionLabel: 'Retry',
///   dismissible: true,
///   onAction: _retry,
///   onLink: _openDocs,
///   onDismiss: _hideAlert,
/// )
///
/// // Programmatic (toast-style)
/// BTAlert.show(
///   context,
///   variant: BTAlertVariant.success,
///   label: 'Profile saved',
/// );
/// ```
class BTAlert extends StatelessWidget {
  const BTAlert({
    required this.label,
    this.variant = BTAlertVariant.info,
    this.description,
    this.linkLabel,
    this.actionLabel,
    this.dismissible = false,
    this.onAction,
    this.onLink,
    this.onDismiss,
    super.key,
  });

  /// Visual style. Defaults to [BTAlertVariant.info].
  final BTAlertVariant variant;

  /// Primary alert message. Bold when [description] is non-null.
  final String label;

  /// Optional supporting text shown below [label].
  final String? description;

  /// Optional inline link shown below [description] (only when [description] is present).
  final String? linkLabel;

  /// Label for the optional action. Renders as a text link when no
  /// [description] is present, or a bordered button when [description] exists.
  final String? actionLabel;

  /// Whether to show a dismiss (×) button on the trailing edge.
  final bool dismissible;

  /// Called when [actionLabel] button / link is tapped.
  final VoidCallback? onAction;

  /// Called when [linkLabel] is tapped.
  final VoidCallback? onLink;

  /// Called when the dismiss button is tapped.
  final VoidCallback? onDismiss;

  // ── Programmatic API ────────────────────────────────────────────────────────

  // Only one toast at a time — dismiss previous before showing a new one.
  static OverlayEntry? _activeEntry;

  /// Show a toast-style alert overlaid at the bottom-right of the screen.
  ///
  /// Only one toast is visible at a time — calling [show] while another toast
  /// is visible immediately replaces it.
  ///
  /// The toast renders on the root overlay (`rootOverlay: true`) so it always
  /// sits above bottom sheets, dialogs, and modals.
  ///
  /// [bottomSpacing] controls the gap between the bottom of the screen and the
  /// alert (default 72). Increase this to account for navigation bars or a
  /// floating action button.
  ///
  /// Returns an [OverlayEntry] that can be manually removed if needed.
  ///
  /// ```dart
  /// BTAlert.show(
  ///   context,
  ///   variant: BTAlertVariant.success,
  ///   label: 'Saved successfully',
  ///   duration: Duration(seconds: 4),
  ///   bottomSpacing: 100,
  /// );
  /// ```
  static OverlayEntry show(
    BuildContext context, {
    required String label,
    BTAlertVariant variant = BTAlertVariant.info,
    String? description,
    String? linkLabel,
    String? actionLabel,
    bool dismissible = true,
    Duration duration = const Duration(seconds: 5),
    double bottomSpacing = 72,
    VoidCallback? onAction,
    VoidCallback? onLink,
  }) {
    // Dismiss any currently visible toast immediately (no reverse animation).
    _activeEntry?.remove();
    _activeEntry = null;

    late final OverlayEntry entry;
    entry = OverlayEntry(
      builder: (_) => BTAlertToast(
        variant: variant,
        label: label,
        description: description,
        linkLabel: linkLabel,
        actionLabel: actionLabel,
        dismissible: dismissible,
        duration: duration,
        bottomSpacing: bottomSpacing,
        onAction: onAction,
        onLink: onLink,
        onClose: () {
          entry.remove();
          if (identical(_activeEntry, entry)) _activeEntry = null;
        },
      ),
    );

    // rootOverlay: true — inserts above all routes (bottom sheets, dialogs, modals).
    Overlay.of(context, rootOverlay: true).insert(entry);
    _activeEntry = entry;
    return entry;
  }

  // ── Token helpers ───────────────────────────────────────────────────────────

  Color _bgColor(BTColorTheme c) => switch (variant) {
        BTAlertVariant.info => c.ext.infoSubtler,
        BTAlertVariant.success => c.ext.successSubtler,
        BTAlertVariant.error => c.ext.errorSubtler,
        BTAlertVariant.warning => c.ext.warningSubtler,
        BTAlertVariant.neutral => c.bg.secondary,
        BTAlertVariant.neutralDark => c.bg.inverse,
      };

  Color? _borderColor(BTColorTheme c) => switch (variant) {
        BTAlertVariant.info => c.ext.infoBold,
        BTAlertVariant.success => c.ext.successBold,
        BTAlertVariant.error => c.ext.errorBold,
        BTAlertVariant.warning => c.ext.warningBold,
        BTAlertVariant.neutral => c.border.primary,
        BTAlertVariant.neutralDark => null, // no border
      };

  Color _iconColor(BTColorTheme c) => switch (variant) {
        BTAlertVariant.info => c.icon.info,
        BTAlertVariant.success => c.icon.success,
        BTAlertVariant.error => c.icon.error,
        BTAlertVariant.warning => c.icon.warning,
        BTAlertVariant.neutral => c.icon.primary,
        BTAlertVariant.neutralDark => c.icon.inverse,
      };

  Color _labelColor(BTColorTheme c) => _iconColor(c);

  Color _descriptionColor(BTColorTheme c) =>
      variant == BTAlertVariant.neutralDark ? c.text.inverse : c.text.primary;

  Color _actionLinkColor(BTColorTheme c) => _iconColor(c);

  String get _iconVariantKey => switch (variant) {
        BTAlertVariant.success => 'success',
        BTAlertVariant.error => 'error',
        BTAlertVariant.warning => 'warning',
        _ => 'info',
      };

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final r = context.btRadius;
    final hasDescription = description != null;
    final borderColor = _borderColor(c);

    return Container(
      decoration: BoxDecoration(
        color: _bgColor(c),
        borderRadius: BorderRadius.circular(r.sm),
        border: borderColor != null
            ? Border.all(color: borderColor)
            : null,
      ),
      padding: EdgeInsets.symmetric(
        horizontal: hasDescription ? 8.0 : 12.0,
        vertical: 8.0,
      ),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // ── Icon ──────────────────────────────────────────────────────────
          BTAlertIcon(variant: _iconVariantKey, color: _iconColor(c)),
          SizedBox(width: 8.0),

          // ── Body ──────────────────────────────────────────────────────────
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              mainAxisSize: MainAxisSize.min,
              children: [
                Text(
                  label,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 14.0,
                    height: 16 / 14,
                    fontWeight:
                        hasDescription ? FontWeight.w700 : FontWeight.w500,
                    color: _labelColor(c),
                  ),
                ),
                if (hasDescription) ...[
                  SizedBox(height: 4.0),
                  Text(
                    description!,
                    style: TextStyle(
                      fontFamily: BTTypography.fontFamily,
                      fontSize: 12.0,
                      height: 16 / 12,
                      fontWeight: FontWeight.w500,
                      color: _descriptionColor(c),
                    ),
                  ),
                  if (linkLabel != null) ...[
                    SizedBox(height: 4.0),
                    variant == BTAlertVariant.neutralDark
                        ? BTButtonLink.invert(label: linkLabel!, onPressed: onLink)
                        : BTButtonLink(label: linkLabel!, onPressed: onLink),
                  ],
                ],
              ],
            ),
          ),

          // ── Action ────────────────────────────────────────────────────────
          if (actionLabel != null) ...[
            SizedBox(width: 8.0),
            if (!hasDescription)
              // BTButtonLink (no description) — textColor drives per-variant hue
              BTButtonLink(
                label: actionLabel!,
                onPressed: onAction,
                textColor: _actionLinkColor(c),
              )
            else
              // BTButton (with description)
              BTButton(
                label: actionLabel!,
                variant: variant == BTAlertVariant.neutralDark
                    ? BTButtonVariant.secondaryLight
                    : BTButtonVariant.outline,
                size: BTButtonSize.sm,
                onPressed: onAction,
              ),
          ],

          // ── Dismiss ───────────────────────────────────────────────────────
          if (dismissible) ...[
            SizedBox(width: 8.0),
            GestureDetector(
              onTap: onDismiss,
              child: Icon(
                Icons.close,
                size: 16,
                color: _iconColor(c),
              ),
            ),
          ],
        ],
      ),
    );
  }
}

import 'package:flutter/material.dart';

/// Icon widget for each [BTAlertVariant] — 16×16 filled Material icon.
///
/// Uses [color] for the icon tint so it inherits the variant's semantic color.
class BTAlertIcon extends StatelessWidget {
  const BTAlertIcon({required this.variant, required this.color, super.key});

  final String variant; // 'info' | 'success' | 'error' | 'warning'
  final Color color;

  @override
  Widget build(BuildContext context) {
    final icon = switch (variant) {
      'success' => Icons.check_circle,
      'error' => Icons.error,
      'warning' => Icons.warning_amber_rounded,
      _ => Icons.info, // info, neutral, neutralDark
    };
    return Icon(icon, size: 16, color: color);
  }
}

